// ===== AGENT TCG CLASSIC =====
const h=$('Limitless Classic').first().json.data;
let prev=null; try{ prev=$('Veille classic').first().json; }catch(e){}
const strip=s=>String(s||'').replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
const now=new Date(), iso=now.toISOString();
const seed=now.getDate()+now.getMonth()*31;
const rows=[...String(h).matchAll(/<tr[\s\S]*?<\/tr>/g)].map(m=>m[0]);
const list=[];
for(const r of rows){
  const a=r.match(/<a[^>]*href="\/decks\/[^"]*"[^>]*>([\s\S]*?)<\/a>/); if(!a) continue;
  const m=strip(r).match(/(\d+)\s+([\d.]+)%\s*$/); if(!m) continue;
  list.push({name:strip(a[1]),points:parseInt(m[1]),share:parseFloat(m[2])});
}
if(list.length<5) throw new Error('Parseur Classic KO ('+list.length+')');
const top=list.slice(0,10);
const cPrev=(prev&&prev.topUsage)||[]; const cr={}; cPrev.forEach((d,i)=>cr[d.name]=i+1);
const withMove=top.map((d,i)=>({rank:i+1,name:d.name,usage:d.share,winrate:null,record:d.points+' pts',winRate:null,share:d.share,
  move:cr[d.name]==null?'new':(cr[d.name]>i+1?'up':(cr[d.name]<i+1?'down':'stable'))}));
const movers=withMove.filter(d=>d.move!=='stable'&&d.move!=='new');
const spot=withMove[seed%withMove.length];
const summary=movers.length
 ? "Du mouvement au classement par points : "+movers.slice(0,2).map(d=>d.name+" ("+(d.move==='up'?'↑':'↓')+")").join(', ')+". "+top[0].name+" reste en tête avec "+top[0].share+"% des points."
 : top[0].name+" verrouille le format ("+top[0].share+"% des points, "+top[0].points+" pts). Pick du jour à étudier : "+spot.name+" ("+spot.share+"%). Données Limitless du "+now.toLocaleDateString('fr-FR')+".";
const out=Object.assign({},prev||{},{metaSummary:summary,topUsage:withMove,topWinrate:[],
 movements:withMove.map(d=>({slug:d.name.toLowerCase().replace(/[^a-z0-9]+/g,'-'),name:d.name,rank:d.rank,usage:d.share,move:d.move})),updatedAt:iso});
out.topDecks=out.topUsage;
return [{json:{content:JSON.stringify(out,null,2),msg:"bot(classic) "+now.toLocaleDateString('fr-FR')+" : "+top[0].name+" "+top[0].share+"%"+(movers.length?", "+movers.length+" mouvements":"")}}];
